t = int(input())

for _ in range(t):
    n = int(input())

    if n < 2:
        print("no")
        continue

    is_prime = True
    for i in range(2, n):   # full loop, no sqrt
        if n % i == 0:
            is_prime = False
            break

    if is_prime:
        print("yes")
    else:
        print("no")

